import { QuantumState } from './QuantumState';
import {
  vqeAnsatz, expectation, exactGroundEnergy, tfimHamiltonian,
  type PauliTerm, type VQEResult,
} from './variational';

/**
 * Analytic gradients via the **parameter-shift rule**.
 *
 * For a gate generated by a Pauli, U(θ) = exp(-i θ/2 P) with P² = I (Rx, Ry, Rz), the exact
 * derivative of any expectation value is
 *
 *     ∂⟨H⟩/∂θ_k = ½ [ ⟨H⟩(θ_k + π/2) − ⟨H⟩(θ_k − π/2) ].
 *
 * This is *exact* (not a finite-difference approximation) and is how real quantum hardware
 * computes gradients — there is no backprop through a physical device. We use it to drive a
 * momentum gradient-descent VQE and verify it against central differences in the test suite.
 */
export function parameterShiftGradient(
  f: (theta: number[]) => number,
  theta: number[],
): number[] {
  const grad = new Array(theta.length).fill(0);
  for (let k = 0; k < theta.length; k++) {
    const plus = theta.slice(); plus[k] += Math.PI / 2;
    const minus = theta.slice(); minus[k] -= Math.PI / 2;
    grad[k] = 0.5 * (f(plus) - f(minus));
  }
  return grad;
}

/** Central finite-difference gradient — reference for validating the parameter-shift rule. */
export function finiteDiffGradient(
  f: (theta: number[]) => number,
  theta: number[],
  h = 1e-5,
): number[] {
  const grad = new Array(theta.length).fill(0);
  for (let k = 0; k < theta.length; k++) {
    const plus = theta.slice(); plus[k] += h;
    const minus = theta.slice(); minus[k] -= h;
    grad[k] = (f(plus) - f(minus)) / (2 * h);
  }
  return grad;
}

export interface GradientDescentOptions {
  lr?: number;
  momentum?: number;
  steps?: number;
  seeds?: number[][];
}

/**
 * VQE driven by analytic gradients + Nesterov-style momentum. Multi-start to dodge the
 * barren/local minima of variational landscapes; returns the best run with a clean energy
 * trace for plotting against the derivative-free Nelder–Mead optimizer.
 */
export function runGradientVQE(
  terms: PauliTerm[] = tfimHamiltonian(),
  opts: GradientDescentOptions = {},
): VQEResult {
  const lr = opts.lr ?? 0.15;
  const momentum = opts.momentum ?? 0.85;
  const steps = opts.steps ?? 60;
  const energyAt = (theta: number[]) => {
    const s = new QuantumState(2);
    for (const op of vqeAnsatz(theta)) s.applyGate(op);
    return expectation(s, terms);
  };
  const seeds = opts.seeds ?? [
    [0.1, 0.1, 0.1, 0.1], [1.5, -1.5, 0.5, 0.5], [2.0, 2.0, -1.0, 1.0],
    [-1.0, 1.0, 2.0, -2.0], [0.8, -0.3, 1.2, 0.4],
  ];

  let best: { energy: number; theta: number[]; trace: { step: number; energy: number }[] } = {
    energy: Infinity, theta: seeds[0].slice(), trace: [],
  };

  for (const seed of seeds) {
    let theta = seed.slice();
    let velocity = new Array(theta.length).fill(0);
    const trace: { step: number; energy: number }[] = [{ step: 0, energy: energyAt(theta) }];
    let bestE = trace[0].energy, bestTheta = theta.slice();
    for (let step = 1; step <= steps; step++) {
      // Nesterov lookahead point.
      const look = theta.map((t, j) => t + momentum * velocity[j]);
      const g = parameterShiftGradient(energyAt, look);
      velocity = velocity.map((v, j) => momentum * v - lr * g[j]);
      theta = theta.map((t, j) => t + velocity[j]);
      const e = energyAt(theta);
      if (e < bestE) { bestE = e; bestTheta = theta.slice(); }
      trace.push({ step, energy: bestE });
    }
    if (bestE < best.energy) best = { energy: bestE, theta: bestTheta, trace };
  }

  return {
    energy: best.energy,
    exact: exactGroundEnergy(2, terms),
    theta: best.theta,
    iterations: best.trace,
  };
}
